<template>
  <div id="Post">
    <section class="post-section">

      <div class="header post-header">
        <h1>{{ $t("Post.title") }}</h1>
        <v-btn @click="CreatePost" class="btn btn-create">
          <v-icon>fal fa-plus-circle</v-icon>
          {{ $t("Post.button") }}
        </v-btn
        >
      </div>

      <div class="post-content">
        <v-data-table
            :headers="$t('Post.table.headers')"
            :items="post['data']"
            :search="searchItem"
            :loading="loading"
            :loading-text="$t('Post.loadingtext')"
            v-if="post['data'] != ''"
        >
          <template v-slot:top>
            <v-toolbar flat>
              <v-text-field
                  :label="$t('Post.txtsearch')"
                  filled
                  rounded
                  dense
                  append-icon="fas fa-search"
                  single-line
                  hide-details
                  v-model="searchItem"
              ></v-text-field>
              <v-spacer></v-spacer>
            </v-toolbar>
          </template>
          <!-- table content -->

          <template v-slot:item="{item , index}">
            <tr class="table-content" v-if="isLaoLanguage">
              <td>{{ index + 1 }}</td>
              <td>
                <v-img :src="item.PostImages[0].image" alt="preview" max-height="50" max-width="50"></v-img>
              </td>
              <td>{{ item.title }}</td>
              <td>{{ item.postTypeId }}</td>
              <td>{{ item.description }}</td>
              <td>{{ item.startDate }}</td>
              <td>{{ item.endDate }}</td>
              <td>{{ item.status }}</td>

              <td>
                <v-menu offset-y>
                  <template v-slot:activator="{on,attrs}">
                    <v-btn icon v-on="on" v-bind="attrs">
                      <v-icon small>fas fa-ellipsis-v</v-icon>
                    </v-btn>
                  </template>
                  <v-list>
                    <v-list-item link @click="$router.push({name:'post.edit',params:{
                     'postId':item.id,
       'descriptionText':item.description,
      'descriptionTextEng':item.PostTrans[0].description,
      'postName':item.title,
      'postNameEng':item.PostTrans[0].title,
      'statusValue':item.status,
      'catePostValue':item.postTypeId,
      'previewImage': item.PostImages,
       'previewImageEng': item.PostImageTrans,
'dateStart':item.startDate,
'dateEnd':item.endDate,}}).catch(()=>{})">
                      <v-list-item-icon>
                        <v-icon class="mr-3" small>{{ $t('Post.table.options.iconEdit') }}</v-icon>
                        <v-list-item-title>
                          {{ $t('Post.title') }}
                        </v-list-item-title>
                      </v-list-item-icon>
                    </v-list-item>
                    <v-list-item link>
                      <v-list-item-icon>
                        <v-icon class="mr-3" small>{{ $t('Post.table.options.delicon') }}</v-icon>
                        <v-list-item-title>
                          {{ $t('Post.table.options.delete') }}
                        </v-list-item-title>
                      </v-list-item-icon>
                    </v-list-item>
                  </v-list>
                </v-menu>
              </td>
            </tr>
            <tr class="table-content" v-else>
              <td>{{ index + 1 }}</td>
              <td>
                <v-img :src="item.PostImageTrans[0].image" alt="preview" max-height="50" max-width="50"></v-img>
              </td>
              <td>{{ item.PostTrans[0].title }}</td>
              <td>{{ item.postTypeId }}</td>
              <td>{{ item.PostTrans[0].description }}</td>
              <td>{{ item.startDate }}</td>
              <td>{{ item.endDate }}</td>
              <td>{{ item.status }}</td>

              <td>
                <v-menu offset-y>
                  <template v-slot:activator="{on,attrs}">
                    <v-btn icon v-on="on" v-bind="attrs">
                      <v-icon small>fas fa-ellipsis-v</v-icon>
                    </v-btn>
                  </template>
                  <v-list>
                    <v-list-item link @click="$router.push({name:'post.edit',params:{
                     'postId':item.id,
       'descriptionText':item.description,
      'descriptionTextEng':item.PostTrans[0].description,
      'postName':item.title,
      'postNameEng':item.PostTrans[0].title,
      'statusValue':item.status,
      'catePostValue':item.postTypeId,
      'previewImage': item.PostImages,
       'previewImageEng': item.PostImageTrans,
'dateStart':item.startDate,
'dateEnd':item.endDate,}}).catch(()=>{})">
                      <v-list-item-icon>
                        <v-icon class="mr-3" small>{{ $t('Post.table.options.iconEdit') }}</v-icon>
                        <v-list-item-title>
                          {{ $t('Post.table.options.edit') }}
                        </v-list-item-title>
                      </v-list-item-icon>
                    </v-list-item>
                    <v-list-item link>
                      <v-list-item-icon>
                        <v-icon class="mr-3" small>{{ $t('Post.table.options.delicon') }}</v-icon>
                        <v-list-item-title>
                          {{ $t('Post.table.options.delete') }}
                        </v-list-item-title>
                      </v-list-item-icon>
                    </v-list-item>
                  </v-list>
                </v-menu>
              </td>
            </tr>
          </template>

        </v-data-table>
        <div class="Table-empty" v-else>
          <div class="image">
            <v-img src="@/assets/Images/NoData.png"></v-img>
          </div>
          <h3>{{ $t("Post.table.dontdata") }}</h3>
        </div>
      </div>
    </section>
  </div>

</template>

<script>
import {mapActions, mapGetters} from 'vuex'

export default {

  name: "Post",

  data() {
    return {
      isLaoLanguage: localStorage.getItem('lang') === 'la',
      image: '@/src/assets/logo.png',
      loading: false,
      searchItem: "",
    };
  },

  mounted() {

    this.getPost()

  },

  methods: {

    CreatePost() {
      this.$router
          .push({
            name: "post.create",
          })
          .catch(() => {
          });
    },

    ...mapActions({
          getPost: 'Post/getPost',
        }
    )
  },
  computed: {
    ...mapGetters({
      post: 'Post/post',
    })
  }
};
</script>

<style lang="scss" scoped>
.post-section {
  width: 100%;
  background-color: $white-color;

  .post-content {
    width: 100%;
    padding: 1rem;

  }
}
</style>
